#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cuda.h>
#include <cuda_runtime.h>
#include "lcutil.h"
#include "mix_kernels_cuda.h"
#include "version_info.h"

#define DEF_VECTOR_SIZE (32*1024*1024)

typedef struct{
	int device_index;
	bool block_strided;
	bool host_allocated;
	bool use_os_timer;
	int wg_size;
	unsigned int vecwidth;
	unsigned int elements_per_wi;
	unsigned int fusion_degree;
} ArgParams;

bool argument_parsing(int argc, char* argv[], ArgParams *output){
	int arg_count = 0;
	for(int i=1; i<argc; i++) {
		if( (strcmp(argv[i], "-h")==0) || (strcmp(argv[i], "--help")==0) ) {
			return false;
		} else if( (strcmp(argv[i], "-w")==0) || (strcmp(argv[i], "--workgroup-stride")==0) ) {
			output->block_strided = true;
		} else if( (strcmp(argv[i], "-H")==0) || (strcmp(argv[i], "--host-alloc")==0) ) {
			output->host_allocated = true;
		} else if( (strcmp(argv[i], "-t")==0) || (strcmp(argv[i], "--use-os-timer")==0) ) {
			output->use_os_timer = true;
		} else {
			unsigned long value = strtoul(argv[i], NULL, 10);
			switch( arg_count ){
				case 0:
					output->device_index = value;
					arg_count++;
					break;
				case 1:
					output->wg_size = value;
					arg_count++;
					break;
				case 2:
					output->vecwidth = value;
					arg_count++;
					break;
				case 3:
					output->elements_per_wi = value;
					arg_count++;
					break;
				case 4:
					output->fusion_degree = value;
					arg_count++;
					break;
				default:
					return false;
			}
		}
	}
	return true;
}

int main(int argc, char* argv[]) {
	printf("mixbench-cuda (%s)\n", VERSION_INFO);

	ArgParams args = {0, false, false, false, 256, DEF_VECTOR_SIZE/(1024*1024), 8, 4};

	if( !argument_parsing(argc, argv, &args) ){
		printf("Usage: mixbench-cuda [options] [device index [workgroup size [array size(1024^2) [elements per workitem [fusion degree]]]]]\n");
		printf("\nOptions:\n"
			"  -h or --help              Show this message\n"
			"  -H or --host-alloc        Use host allocated buffer (cudaHostAlloc)\n"
			"  -w or --workgroup-stride  Workitem strides equal to the width of a workgroup length (default: NDRange length)\n"
			"  -t or --use-os-timer      Use standard OS timer instead of CUDA event timer\n"
			"\n");

		int deviceCount = 0;
		cudaGetDeviceCount(&deviceCount);
		printf("Available CUDA devices:\n");
		for(int d=0; d<deviceCount; d++){
			cudaDeviceProp prop;
			cudaGetDeviceProperties(&prop, d);
			printf("  %d. %s\n", d, prop.name);
		}
		exit(1);
	}

	printf("Use \"-h\" argument to see available options\n");

	const size_t VEC_WIDTH = 1024*1024*args.vecwidth;
	unsigned int datasize = VEC_WIDTH*sizeof(double);

	int deviceCount = 0;
	CUDA_SAFE_CALL(cudaGetDeviceCount(&deviceCount));
	if(args.device_index < 0 || args.device_index >= deviceCount){
		fprintf(stderr, "Error: No CUDA device selected or invalid device index\n");
		exit(1);
	}
	CUDA_SAFE_CALL(cudaSetDevice(args.device_index));
	StoreDeviceInfo(stdout);

	printf("Buffer size:            %dMB\n", datasize/(1024*1024));
	printf("Workgroup size:         %d\n", args.wg_size);
	printf("Elements per workitem:  %d\n", args.elements_per_wi);
	printf("Workitem fusion degree: %d\n", args.fusion_degree);

	// We cannot easily query max thread block size here, but we trust user input or could check below
	// int maxThreadsPerBlock;
	// cudaDeviceGetAttribute(&maxThreadsPerBlock, cudaDevAttrMaxThreadsPerBlock, args.device_index);
	// if(maxThreadsPerBlock < args.wg_size){
	//	fprintf(stderr, "Error: Unsupported workgroup size (%u).\n", args.wg_size);
	//	exit(1);
	//}

	double *c;
	if(args.host_allocated){
		CUDA_SAFE_CALL(cudaHostAlloc((void **)&c, datasize, cudaHostAllocDefault));
	} else {
		c = (double*)malloc(datasize);
	}

	mixbenchGPU(c, VEC_WIDTH);

	if(args.host_allocated){
		CUDA_SAFE_CALL(cudaFreeHost(c));
	} else {
		free(c);
	}

	return 0;
}
